390→void ALFPWorldMapPlayerController::ShowReachableNodes()
391→{
392→	ClearReachableHighlight();
393→
394→	ALFPWorldMapManager* Manager = GetWorldMapManager();
395→	if (!Manager || !Manager->GetPlayerState()) return;
396→
397→	TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
398→	for (int32 NodeID : ReachableIDs)
399→	{
400→		if (ALFPWorldMapNode* Node = Manager->GetNode(NodeID))
401→		{
402→			Node->SetHighlighted(true);
403→			ReachableNodes.Add(Node);
404→		}
405→	}
406→}
