186→
187→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
188→{
189→	// 统计每个 TypeID 的出现次数
190→	TMap<FName, int32> CountMap;
191→
192→	for (const FLFPUnitEntry& Unit : PartyUnits)
193→	{
194→		if (Unit.IsValid())
195→		{
196→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
197→		}
198→	}
199→	for (const FLFPUnitEntry& Unit : ReserveUnits)
200→	{
201→		if (Unit.IsValid())
202→		{
203→			CountMap.FindOrAdd(Unit.TypeID, 0)++;
204→		}
205→	}
206→
207→	// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
208→	TArray<FLFPUnitEntry> Result;
209→	for (const auto& Pair : CountMap)
210→	{
211→		if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
212→		{
213→			FLFPUnitEntry Entry;
214→			Entry.TypeID = Pair.Key;
215→			Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
216→			Result.Add(Entry);
217→		}
218→	}
219→
220→	return Result;
221→}
222→
223→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex,
224→	bool bSourceBIsParty, int32 SourceBIndex, FName TargetTypeID)
225→{
226→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
227→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
228→
229→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
230→	{
231→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
232→		return false;
233→	}
234→
235→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
236→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
237→
238→	// 验证两个源单位 TypeID 相同
239→	if (UnitA.TypeID != UnitB.TypeID)
240→	{
241→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位类型不匹配 (%s vs %s)"),
242→			*UnitA.TypeID.ToString(), *UnitB.TypeID.ToString());
243→		return false;
244→	}
245→
246→	// 验证 TargetTypeID 在进化目标列表中
247→	if (!UnitRegistry)
248→	{
249→		UE_LOG(LogTemp, Error, TEXT("MergeUnits: 注册表未配置"));
250→		return false;
251→	}
252→
253→	TArray<FName> Targets = UnitRegistry->GetEvolutionTargets(UnitA.TypeID);
254→	if (!Targets.Contains(TargetTypeID))
255→	{
256→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: %s 不是 %s 的有效进化目标"),
257→			*TargetTypeID.ToString(), *UnitA.TypeID.ToString());
258→		return false;
259→	}
260→
261→	// 创建进化后的新单位
262→	FLFPUnitEntry NewUnit;
263→	NewUnit.TypeID = TargetTypeID;
264→	NewUnit.Tier = UnitRegistry->GetUnitTier(TargetTypeID);
265→
266→	// 移除两个源单位（同一数组时先移除大索引避免偏移）
267→	if (bSourceAIsParty == bSourceBIsParty)
268→	{
269→		int32 First = FMath::Max(SourceAIndex, SourceBIndex);
270→		int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
271→		ArrayA.RemoveAt(First);
272→		ArrayA.RemoveAt(Second);
273→	}
274→	else
275→	{
276→		ArrayA.RemoveAt(SourceAIndex);
277→		ArrayB.RemoveAt(SourceBIndex);
278→	}
279→
280→	TryAddUnit(NewUnit);
281→
282→	UE_LOG(LogTemp, Log, TEXT("进化成功: %s × 2 → %s (T%d)"),
283→		*UnitA.TypeID.ToString(), *TargetTypeID.ToString(), NewUnit.Tier);
284→
285→	return true;
286→}
