 81→void ALFPWorldMapGameMode::HandleBattleResult(const FLFPBattleResult& Result)
 82→{
 83→	if (!WorldMapManager) return;
 84→
 85→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 86→
 87→	UE_LOG(LogTemp, Log, TEXT("处理战斗结果: 节点 %d, 胜利=%s, 逃跑=%s"),
 88→		Result.SourceNodeID,
 89→		Result.bVictory ? TEXT("是") : TEXT("否"),
 90→		Result.bEscaped ? TEXT("是") : TEXT("否"));
 91→
 92→	if (Result.bVictory)
 93→	{
 94→		// 胜利：节点标记为已触发（如果尚未标记）
 95→		ALFPWorldMapNode* Node = WorldMapManager->GetNode(Result.SourceNodeID);
 96→		if (Node && !Node->bHasBeenTriggered)
 97→		{
 98→			Node->bHasBeenTriggered = true;
 99→			Node->UpdateVisualState();
100→		}
101→
102→		// 发放奖励到 GameInstance
103→		if (GI)
104→		{
105→			GI->AddGold(Result.GoldReward);
106→			GI->AddFood(Result.FoodReward);
107→			UE_LOG(LogTemp, Log, TEXT("战斗奖励: 金币 +%d, 食物 +%d"), Result.GoldReward, Result.FoodReward);
108→		}
109→
110→		// 处理捕获的单位
111→		if (Result.CapturedUnits.Num() > 0)
112→		{
113→			ProcessCapturedUnits(Result.CapturedUnits);
114→		}
115→	}
116→	else if (Result.bEscaped)
117→	{
118→		// 逃跑：不标记为已触发，可再次进入，不发放奖励
119→		UE_LOG(LogTemp, Log, TEXT("逃跑：节点 %d 未标记为已触发"), Result.SourceNodeID);
120→	}
121→	else
122→	{
123→		// 失败：不标记节点，可重试，不发放奖励
124→		UE_LOG(LogTemp, Warning, TEXT("战斗失败：节点 %d，可重试"), Result.SourceNodeID);
125→	}
126→}
