 68→		{
 69→			bIsTransitioning = false;
 70→			UGameplayStatics::OpenLevel(this, FName(*CapturedLevelName));
 71→		}, TransitionFadeDuration, false);
 72→	}
 73→	else
 74→	{
 75→		bIsTransitioning = false;
 76→		UGameplayStatics::OpenLevel(this, FName(*LevelName));
 77→	}
